INSERT INTO exercise (
    id, version_number, is_deleted, blocks, interaction
)
VALUES
    (
        '40aaa000-0000-4000-a000-000000000001',
        1,
        false,
        '[
            {
                "clientId": "50100000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Welcome to JavaScript!"
            },
            {
                "clientId": "50100000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "JavaScript is the most popular programming language for web development. In this lesson you will learn how to store data using variables and constants."
            }
        ]'::jsonb,
        NULL
    ),
    (
        '40aaa000-0000-4000-a000-000000000002',
        1,
        false,
        '[
            {
                "clientId": "50200000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Declaring Variables"
            },
            {
                "clientId": "50200000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "In modern JavaScript we use `let` to declare variables that can be reassigned, and `const` for values that never change."
            },
            {
                "clientId": "50200000-0003-4000-a000-000000000000",
                "type": "code",
                "language": "javascript",
                "content": "let score = 0;\nscore = 10;\nconsole.log(score);",
                "output": "10"
            },
            {
                "clientId": "50200000-0004-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Which keyword declares a variable that can be reassigned?"
            }
        ]'::jsonb,
        '{
            "type": "SELECT",
            "clientId": "60200000-0000-4000-a000-000000000000",
            "items": ["let", "const", "var", "function"],
            "correctValue": "let"
        }'::jsonb
    ),
    (
        '40aaa000-0000-4000-a000-000000000003',
        1,
        false,
        '[
            {
                "clientId": "50300000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Creating a Constant"
            },
            {
                "clientId": "50300000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Use `const` when you know the value should never change after it is assigned."
            }
        ]'::jsonb,
        '{
            "type": "CLOZE",
            "clientId": "60300000-0000-4000-a000-000000000000",
            "file": {
                "language": "javascript",
                "content": "___ PI = 3.14159;"
            },
            "blanks": [
                {
                    "index": 0,
                    "correctOptions": ["const"]
                }
            ],
            "options": ["let", "const", "var"]
        }'::jsonb
    ),
    (
        '40aaa000-0000-4000-a000-000000000004',
        1,
        false,
        '[
            {
                "clientId": "50400000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Variable Naming"
            },
            {
                "clientId": "50400000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Variable names can contain letters, digits, underscores, and dollar signs. They must begin with a letter, underscore, or dollar sign."
            },
            {
                "clientId": "50400000-0003-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Which of these is a valid variable name?"
            }
        ]'::jsonb,
        '{
            "type": "SELECT",
            "clientId": "60400000-0000-4000-a000-000000000000",
            "items": ["myScore", "2fast", "my-var", "class"],
            "correctValue": "myScore"
        }'::jsonb
    ),
    (
        '40aaa000-0000-4000-a000-000000000005',
        1,
        false,
        '[
            {
                "clientId": "50500000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Using Variables"
            },
            {
                "clientId": "50500000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Variables can store the results of expressions and be updated over time."
            }
        ]'::jsonb,
        '{
            "type": "CLOZE",
            "clientId": "60500000-0000-4000-a000-000000000000",
            "file": {
                "language": "javascript",
                "content": "let width = 10;\nlet height = 5;\nlet area = width ___ height;\nconsole.log(area);"
            },
            "blanks": [
                {
                    "index": 0,
                    "correctOptions": ["*"]
                }
            ],
            "options": ["*", "+", "/", "="],
            "output": "50"
        }'::jsonb
    )
ON CONFLICT DO NOTHING;

INSERT INTO exercise (
    id, version_number, is_deleted, blocks, interaction
)
VALUES
    (
        '40aaa000-0000-4000-a000-000000000006',
        1,
        false,
        '[
            {
                "clientId": "50600000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Data Types in JavaScript"
            },
            {
                "clientId": "50600000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Every value in JavaScript has a type. The main types are: string, number, boolean, null, and undefined. Understanding types helps you write bug-free code."
            }
        ]'::jsonb,
        NULL
    ),
    -- E7: Strings (SELECT)
    (
        '40aaa000-0000-4000-a000-000000000007',
        1,
        false,
        '[
            {
                "clientId": "50700000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Strings"
            },
            {
                "clientId": "50700000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Strings represent text. You can create them with double quotes, single quotes, or backticks."
            },
            {
                "clientId": "50700000-0003-4000-a000-000000000000",
                "type": "code",
                "language": "javascript",
                "content": "let greeting = \"Hello!\";\nconsole.log(typeof greeting);",
                "output": "string"
            },
            {
                "clientId": "50700000-0004-4000-a000-000000000000",
                "type": "paragraph",
                "content": "What does `typeof 42` return?"
            }
        ]'::jsonb,
        '{
            "type": "SELECT",
            "clientId": "60700000-0000-4000-a000-000000000000",
            "items": ["number", "string", "integer", "float"],
            "correctValue": "number"
        }'::jsonb
    ),
    -- E8: The typeof Operator (CLOZE)
    (
        '40aaa000-0000-4000-a000-000000000008',
        1,
        false,
        '[
            {
                "clientId": "50800000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "The typeof Operator"
            },
            {
                "clientId": "50800000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "The `typeof` operator returns a string that describes the type of a value."
            }
        ]'::jsonb,
        '{
            "type": "CLOZE",
            "clientId": "60800000-0000-4000-a000-000000000000",
            "file": {
                "language": "javascript",
                "content": "let active = true;\nconsole.log(___ active);"
            },
            "blanks": [
                {
                    "index": 0,
                    "correctOptions": ["typeof"]
                }
            ],
            "options": ["typeof", "type", "typeOf", "class"],
            "output": "boolean"
        }'::jsonb
    ),
    -- E9: Booleans (SELECT)
    (
        '40aaa000-0000-4000-a000-000000000009',
        1,
        false,
        '[
            {
                "clientId": "50900000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Booleans"
            },
            {
                "clientId": "50900000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Booleans represent `true` or `false`. They are commonly used in conditions and comparisons."
            },
            {
                "clientId": "50900000-0003-4000-a000-000000000000",
                "type": "code",
                "language": "javascript",
                "content": "let x = 10;\nlet y = 5;\nconsole.log(x > y);"
            },
            {
                "clientId": "50900000-0004-4000-a000-000000000000",
                "type": "paragraph",
                "content": "What will `x > y` evaluate to?"
            }
        ]'::jsonb,
        '{
            "type": "SELECT",
            "clientId": "60900000-0000-4000-a000-000000000000",
            "items": ["true", "false", "undefined", "null"],
            "correctValue": "true"
        }'::jsonb
    ),
    -- E10: String Concatenation (CLOZE)
    (
        '40aaa000-0000-4000-a000-00000000000a',
        1,
        false,
        '[
            {
                "clientId": "50a00000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "String Concatenation"
            },
            {
                "clientId": "50a00000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "You can combine strings together using the `+` operator."
            }
        ]'::jsonb,
        '{
            "type": "CLOZE",
            "clientId": "60a00000-0000-4000-a000-000000000000",
            "file": {
                "language": "javascript",
                "content": "let first = \"Hello\";\nlet second = \"World\";\nlet result = first + \" \" ___ second;\nconsole.log(result);"
            },
            "blanks": [
                {
                    "index": 0,
                    "correctOptions": ["+"]
                }
            ],
            "options": ["+", "-", "*", "="],
            "output": "Hello World"
        }'::jsonb
    )
ON CONFLICT DO NOTHING;

INSERT INTO exercise (
    id, version_number, is_deleted, blocks, interaction
)
VALUES
    (
        '40aaa000-0000-4000-a000-00000000000b',
        1,
        false,
        '[
            {
                "clientId": "50b00000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Step 1: The Add Function"
            },
            {
                "clientId": "50b00000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Create a function that adds two numbers and prints the result."
            },
            {
                "clientId": "50b00000-0003-4000-a000-000000000000",
                "type": "instructions",
                "instructions": [
                    "Create a function called `add` that takes parameters `a` and `b`",
                    "Return the sum of `a` and `b`",
                    "Call `add(3, 5)` and print the result with `console.log`"
                ]
            }
        ]'::jsonb,
        '{
            "type": "EXECUTABLE",
            "clientId": "60b00000-0000-4000-a000-000000000000",
            "solution": "function add(a, b) {\n  return a + b;\n}\nconsole.log(add(3, 5));",
            "tests": [
                {
                    "type": "OUTPUT_CONTAINS",
                    "expected": "8",
                    "feedback": "Make sure your add function returns a + b and you print the result of add(3, 5)."
                }
            ],
            "showOutput": true
        }'::jsonb
    ),
    (
        '40aaa000-0000-4000-a000-00000000000c',
        1,
        false,
        '[
            {
                "clientId": "50c00000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Step 2: The Subtract Function"
            },
            {
                "clientId": "50c00000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Now add a subtract function to your calculator."
            },
            {
                "clientId": "50c00000-0003-4000-a000-000000000000",
                "type": "instructions",
                "instructions": [
                    "Create a function called `subtract` that takes parameters `a` and `b`",
                    "Return the result of `a - b`",
                    "Call `subtract(10, 4)` and print the result"
                ]
            }
        ]'::jsonb,
        '{
            "type": "EXECUTABLE",
            "clientId": "60c00000-0000-4000-a000-000000000000",
            "solution": "function add(a, b) {\n  return a + b;\n}\n\nfunction subtract(a, b) {\n  return a - b;\n}\nconsole.log(subtract(10, 4));",
            "tests": [
                {
                    "type": "OUTPUT_CONTAINS",
                    "expected": "6",
                    "feedback": "Make sure your subtract function returns a - b and you print the result of subtract(10, 4)."
                }
            ],
            "showOutput": true
        }'::jsonb
    ),
    (
        '40aaa000-0000-4000-a000-00000000000d',
        1,
        false,
        '[
            {
                "clientId": "50d00000-0001-4000-a000-000000000000",
                "type": "header",
                "content": "Step 3: The Multiply Function"
            },
            {
                "clientId": "50d00000-0002-4000-a000-000000000000",
                "type": "paragraph",
                "content": "Complete your calculator with a multiply function."
            },
            {
                "clientId": "50d00000-0003-4000-a000-000000000000",
                "type": "instructions",
                "instructions": [
                    "Create a function called `multiply` that takes parameters `a` and `b`",
                    "Return the product of `a` and `b`",
                    "Call `multiply(7, 6)` and print the result"
                ]
            }
        ]'::jsonb,
        '{
            "type": "EXECUTABLE",
            "clientId": "60d00000-0000-4000-a000-000000000000",
            "solution": "function add(a, b) {\n  return a + b;\n}\n\nfunction subtract(a, b) {\n  return a - b;\n}\n\nfunction multiply(a, b) {\n  return a * b;\n}\nconsole.log(multiply(7, 6));",
            "tests": [
                {
                    "type": "OUTPUT_CONTAINS",
                    "expected": "42",
                    "feedback": "Make sure your multiply function returns a * b and you print the result of multiply(7, 6)."
                }
            ],
            "showOutput": true
        }'::jsonb
    )
ON CONFLICT DO NOTHING;
